function toReviewFindingRecord(value: unknown): ReviewFinding[] {
  if (!Array.isArray(value)) {
    return [];
  }

  // Phase 2 contract: strict V2 query surfaces intentionally exclude legacy finding shapes.
  // We do not attempt semantic V1->V2 conversion at read time because legacy reports were
  // generated without full ReviewContext and are not trustworthy for canonical V2 semantics.
  return value.flatMap((item) => {
    const record = item && typeof item === 'object' && !Array.isArray(item) ? (item as Record<string, unknown>) : null;
    if (!record) {
      return [];
    }

    const severity = typeof record.severity === 'string' ? record.severity.trim() : '';
    const category = typeof record.category === 'string' ? record.category.trim() : '';
    const passType = typeof record.passType === 'string' ? record.passType.trim() : '';
    const description = typeof record.description === 'string' ? record.description.trim() : '';
    const suggestedFix = typeof record.suggestedFix === 'string' ? record.suggestedFix.trim() : '';
    if (!severity || !category || !passType || !description) {
      return [];
    }

    if (!['info', 'low', 'medium', 'high', 'critical'].includes(severity)) {
      return [];
    }
    if (!['security', 'logic', 'style', 'breaking-change'].includes(category)) {
      return [];
    }
    if (passType !== 'single') {
      return [];
    }

    const locationsRaw = Array.isArray(record.locations) ? record.locations : [];
    const locations = locationsRaw.flatMap((locationItem) => {
      const location =
        locationItem && typeof locationItem === 'object' && !Array.isArray(locationItem)
          ? (locationItem as Record<string, unknown>)
          : null;
      if (!location) {
        return [];
      }

      const filePath = typeof location.filePath === 'string' ? location.filePath.trim() : '';
      if (!filePath) {
        return [];
      }
      const startLine = location.startLine;
      const endLine = location.endLine;
      const nullRange = startLine === null && endLine === null;
      const numericRange =
        typeof startLine === 'number' &&
        Number.isInteger(startLine) &&
        startLine > 0 &&
        typeof endLine === 'number' &&
        Number.isInteger(endLine) &&
        endLine >= startLine;
      if (!nullRange && !numericRange) {
        return [];
      }

      return [
        {
          filePath,
          startLine: nullRange ? null : (startLine as number),
          endLine: nullRange ? null : (endLine as number),
        },
      ];
    });

    if (locations.length === 0) {
      return [];
    }

    return [
      {
        severity: severity as ReviewFinding['severity'],
        category: category as ReviewFinding['category'],
        passType: passType as ReviewFinding['passType'],
        locations,
        description,
        suggestedFix,
      },
    ];
  });
}

function toReviewRunResponse(record: ReviewRunRecord): ReviewRunResponse {
  const provenance = parseJsonOrFallback(record.provenance_json, {});
  const report = parseJsonOrFallback(record.report_json, null) as ReviewReport | null;
  const reportHasProvenance = Boolean(report?.provenance);

  const response: ReviewRunResponse = {
    id: record.id,
    workspaceId: record.workspace_id,
    deploymentId: record.deployment_id,
    target: {
      type: record.target_type,
      workspaceId: record.workspace_id,
      deploymentId: record.deployment_id,
    },
    mode: record.mode,
    status: record.status,
    idempotencyKey: record.idempotency_key,
    attemptCount: record.attempt_count,
    startedAt: record.started_at,
    finishedAt: record.finished_at,
    createdAt: record.created_at,
    updatedAt: record.updated_at,
    findings: toReviewFindingRecord(report?.findings),
    evidence: Array.isArray(report?.evidence) ? report.evidence : [],
    provenance: {
      sessionIds:
        report?.provenance && Array.isArray(report.provenance.sessionIds) ? report.provenance.sessionIds : [],
      promptSummary:
        report?.provenance && typeof report.provenance.promptSummary === 'string'
          ? report.provenance.promptSummary
          : !reportHasProvenance && typeof (provenance as Record<string, unknown>).promptSummary === 'string'
            ? ((provenance as Record<string, unknown>).promptSummary as string)
            : null,
      transcriptUrl:
        report?.provenance && typeof report.provenance.transcriptUrl === 'string'
          ? report.provenance.transcriptUrl
          : null,
      reviewContextRef:
        report?.provenance && report.provenance.reviewContextRef && typeof report.provenance.reviewContextRef === 'object'
          ? (report.provenance.reviewContextRef as ReviewContextRef)
          : null,
      reviewContextStats:
        report?.provenance && report.provenance.reviewContextStats && typeof report.provenance.reviewContextStats === 'object'
          ? report.provenance.reviewContextStats
          : undefined,
    },
    markdownSummary: record.markdown_summary,
  };

  if (report?.summary) {
    response.summary = report.summary;
  }
  if (typeof report?.summaryText === 'string') {
    response.summaryText = report.summaryText;
  }
  if (typeof report?.furtherPassesLowYield === 'boolean') {
    response.furtherPassesLowYield = report.furtherPassesLowYield;
  }
  if (report?.intent) {
    response.intent = report.intent;
  }
  if (record.error_code && record.error_message) {
    response.error = {
      code: record.error_code,
      message: record.error_message,
    };
  }

  return response;
}

/**
 * Create a new checkpoint job in the database
 */
export async function createCheckpointJob(
  db: D1Database,
  input: CreateCheckpointJobInput
): Promise<JobResponse> {
  const result = await db
    .prepare(
      `INSERT INTO jobs (
         id,
         prompt,
         model,
         status,
         phase,
         source_type,
         checkpoint_id,
         commit_sha,
         source_ref,
         source_project_root,
         build_run_tests_if_present,
         build_run_lint_if_present,
         source_bundle_key,
         source_bundle_sha256,
         source_bundle_bytes
       )
       VALUES (?, ?, 'checkpoint', 'queued', 'queued', 'checkpoint', ?, ?, ?, ?, ?, ?, ?, ?, ?)
       RETURNING *`
    )
    .bind(
      input.id,
      input.prompt,
      input.checkpointId,
      input.commitSha,
      input.sourceRef ?? null,
      input.sourceProjectRoot ?? null,
      input.buildRunTestsIfPresent ? 1 : 0,
      input.buildRunLintIfPresent ? 1 : 0,
      input.sourceBundleKey,
      input.sourceBundleSha256,
      input.sourceBundleBytes
    )
    .first<JobRecord>();

  if (!result) {
    throw new Error('Failed to create checkpoint job');
  }

  return toJobResponse(result);
}

/**
 * Get a job by ID
 */
export async function getJob(db: D1Database, id: string): Promise<JobResponse | null> {
  const result = await db
    .prepare('SELECT * FROM jobs WHERE id = ?')
    .bind(id)
    .first<JobRecord>();

  if (!result) {
    return null;
  }

  return toJobResponse(result);
}

/**
 * List all jobs, most recent first
 */
export async function listJobs(db: D1Database, limit = 50): Promise<JobListItem[]> {
  const result = await db
    .prepare('SELECT * FROM jobs ORDER BY created_at DESC LIMIT ?')
    .bind(limit)
    .all<JobRecord>();

  return result.results.map(toJobListItem);
}

/**
 * Delete a job by ID
 */
export async function deleteJob(db: D1Database, id: string): Promise<void> {
  await db.prepare('DELETE FROM jobs WHERE id = ?').bind(id).run();
}

/**
 * Atomically claim a queued checkpoint job for execution.
 * Returns true when claim succeeds, false when another worker already claimed.
 */
export async function claimQueuedCheckpointJob(db: D1Database, id: string): Promise<boolean> {
  const result = await db
    .prepare(
      `UPDATE jobs
       SET status = 'running',
           phase = 'building',
           started_at = ?,
           error_message = NULL,
           error_code = NULL
       WHERE id = ? AND status = 'queued'`
    )
    .bind(new Date().toISOString(), id)
    .run();

  const changes = Number((result as { meta?: { changes?: number } }).meta?.changes ?? 0);
  return changes > 0;
}

/**
 * Append a sequenced job event and return its sequence number.
 */
export async function appendJobEvent(
  db: D1Database,
  input: {
    jobId: string;
    attemptNo?: number;
    eventType: string;
    phase: JobPhase;
    payload: unknown;
  }
): Promise<number> {
  const sequenceResult = await db
    .prepare('UPDATE jobs SET last_event_seq = last_event_seq + 1 WHERE id = ? RETURNING last_event_seq')
    .bind(input.jobId)
    .first<{ last_event_seq: number }>();

  if (!sequenceResult) {
    throw new Error(`Failed to allocate event sequence for job ${input.jobId}`);
  }

  const seq = Number(sequenceResult.last_event_seq);
  await db
    .prepare(
      `INSERT INTO job_events (job_id, attempt_no, seq, event_type, phase, payload_json)
       VALUES (?, ?, ?, ?, ?, ?)`
    )
    .bind(
      input.jobId,
      input.attemptNo ?? 0,
      seq,
      input.eventType,
      input.phase,
      JSON.stringify(input.payload)
    )
    .run();

  return seq;
}

/**
 * List persisted job events from a given sequence.
 */
export async function listJobEvents(
  db: D1Database,
  jobId: string,
  fromExclusive = 0,
  limit = 500
): Promise<JobEventItem[]> {
  const result = await db
    .prepare(
      `SELECT id, job_id, attempt_no, seq, event_type, phase, payload_json, created_at
       FROM job_events
       WHERE job_id = ? AND seq > ?
       ORDER BY seq ASC
       LIMIT ?`
    )
    .bind(jobId, fromExclusive, limit)
    .all<JobEventRecord>();

  return result.results.map((row) => {
    let payload: unknown;
    try {
      payload = JSON.parse(row.payload_json);
    } catch {
      payload = { raw: row.payload_json };
    }

    return {
      seq: row.seq,
      eventType: row.event_type,
      phase: row.phase,
      payload,
      createdAt: row.created_at,
    };
  });
}

/**
 * Update job status
 */
export async function updateJobStatus(
  db: D1Database,
  id: string,
  status: JobStatus,
  additionalFields?: {
    phase?: JobPhase;
    started_at?: string | null;
    completed_at?: string | null;
    cancel_requested_at?: string | null;
    cancelled_at?: string | null;
    preview_url?: string;
    deployed_url?: string;
    code_url?: string;
    code_zip_url?: string;
    error_message?: string | null;
    error_code?: string | null;
    retry_count?: number;
    file_count?: number;
    // Metrics fields
    prompt_tokens?: number;
    completion_tokens?: number;
    total_tokens?: number;
    cost?: number;
    llm_latency_ms?: number;
    install_duration_ms?: number;
    build_duration_ms?: number;
    deploy_duration_ms?: number;
    total_duration_ms?: number;
    lines_of_code?: number;
  }
): Promise<void> {
  const updates: string[] = ['status = ?'];
  const values: (string | number | null)[] = [status];

  if (additionalFields) {
    if (additionalFields.phase !== undefined) {
      updates.push('phase = ?');
      values.push(additionalFields.phase);
    }
    if (additionalFields.started_at !== undefined) {
      updates.push('started_at = ?');
      values.push(additionalFields.started_at);
    }
    if (additionalFields.completed_at !== undefined) {
      updates.push('completed_at = ?');
      values.push(additionalFields.completed_at);
    }
    if (additionalFields.cancel_requested_at !== undefined) {
      updates.push('cancel_requested_at = ?');
      values.push(additionalFields.cancel_requested_at);
    }
    if (additionalFields.cancelled_at !== undefined) {
