export async function getWorkspaceTaskRequestPayload(
  db: D1Database,
  taskId: string
): Promise<Record<string, unknown> | null> {
  const record = await db
    .prepare('SELECT request_payload_json FROM workspace_tasks WHERE id = ?')
    .bind(taskId)
