       FROM review_events
       WHERE review_id = ? AND seq > ?
       ORDER BY seq ASC
       LIMIT ?`
    )
    .bind(reviewId, fromExclusive, limit)
    .all<ReviewEventRecord>();

  return result.results.map((row) => {
    let payload: unknown;
    try {
