    for (const dir of dirs) {
      for (const pattern of CONVENTION_PATTERNS) {
        const candidate = dir ? `${dir}/${pattern}` : pattern;
        candidates.add(candidate);
        if (candidates.size >= maxCount * 6) {
          return Array.from(candidates);
